const lead = $input.item.json;
const crypto = require('crypto');
const input_hash = crypto.createHash('sha256').update(`${lead.email}|${lead.name}|${lead.message || ''}`).digest('hex');
return [{
  json: {
    ...lead,
    input_hash,
    ai_prompt: `Analyze this B2B SaaS lead. Return JSON only.
Name: ${lead.name}
Email: ${lead.email}
Company: ${lead.company} (size: ${lead.company_size})
Message: ${lead.message || 'N/A'}

Schema:
{
  "lead_score": 0-100,
  "intent_category": "high_buying" | "medium_interest" | "low_info" | "spam",
  "summary": "one sentence",
  "recommended_action": "Call immediately" | "Send email" | "Nurture",
  "confidence": 0.0-1.0
}`
  }
}];

const lead = $('Fetch Validated Leads').item.json;
const input_hash = $('Build AI Prompt').item.json.input_hash;
const aiRaw = $input.first().json.text || $input.first().json.output || '';
let parsed = {};
try {
  parsed = JSON.parse(String(aiRaw).replace(/```json|```/g, '').trim());
} catch (e) {
  parsed = { lead_score: 50, intent_category: 'low_info', summary: 'AI parse failed', recommended_action: 'Nurture', confidence: 0 };
}
let lead_score = Math.min(100, Math.max(0, parseInt(parsed.lead_score, 10) || 0));
const confidence = Number(parsed.confidence) || 0;
const intent_category = parsed.intent_category || 'low_info';
let requires_human_review = confidence < 0.6;
if (intent_category === 'spam') {
  lead_score = Math.min(lead_score, 20);
  requires_human_review = true;
}
const notify_slack = lead_score >= 80 && confidence >= 0.6 && intent_category !== 'spam';
return [{
  json: {
    lead_id: lead.id,
    name: lead.name,
    email: lead.email,
    lead_score,
    intent_category,
    summary: parsed.summary || '',
    recommended_action: parsed.recommended_action || 'Nurture',
    requires_human_review,
    notify_slack,
    input_hash,
    ai_output: parsed,
    model_version: 'gpt-4o-mini',
    status: 'qualified'
  }
}];

